import React, { useState, useEffect } from 'react';
import { fetchLogs, fetchStats } from './services/api';
import LogTable from './components/LogTable';
import StatsOverview from './components/StatsOverview';
import { RefreshCw, ShieldAlert, ListFilter } from 'lucide-react';

function App() {
  const [logs, setLogs] = useState([]);
  const [stats, setStats] = useState(null);
  const [severityFilter, setSeverityFilter] = useState('');
  const [loading, setLoading] = useState(true);

  const loadData = async () => {
    setLoading(true);
    try {
      const [newLogs, newStats] = await Promise.all([
        fetchLogs({ severity: severityFilter }),
        fetchStats()
      ]);
      setLogs(newLogs);
      setStats(newStats);
    } catch (err) {
      console.error('Failed to load dashboard data:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 5000); // Auto-refresh every 5 seconds
    return () => clearInterval(interval);
  }, [severityFilter]);

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <ShieldAlert className="text-blue-600 h-8 w-8" />
            <h1 className="text-xl font-black uppercase tracking-tighter">SMA Intelligence</h1>
          </div>
          <button 
            onClick={loadData}
            className={`p-2 rounded-full hover:bg-gray-100 transition-colors ${loading ? 'animate-spin' : ''}`}
          >
            <RefreshCw className="h-5 w-5 text-gray-400" />
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Filters and Controls */}
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center space-x-4 bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
            <div className="flex items-center px-3 text-gray-400 border-r border-gray-100">
              <ListFilter className="h-4 w-4 mr-2" />
              <span className="text-xs font-bold uppercase">Filter By</span>
            </div>
            {['', 'Severe', 'High', 'Medium', 'Low'].map((level) => (
              <button
                key={level}
                onClick={() => setSeverityFilter(level)}
                className={`px-3 py-1 text-sm font-semibold rounded-md transition-all ${
                  severityFilter === level 
                    ? 'bg-blue-600 text-white shadow-md' 
                    : 'text-gray-500 hover:text-gray-900'
                }`}
              >
                {level || 'All'}
              </button>
            ))}
          </div>
        </div>

        {/* Overview Stats */}
        <StatsOverview stats={stats} />

        {/* Log Stream */}
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-sm font-bold text-gray-500 uppercase tracking-widest flex items-center">
            Live Intelligence Stream
            {loading && <span className="ml-3 h-2 w-2 bg-blue-500 rounded-full animate-pulse"></span>}
          </h3>
          <span className="text-xs text-gray-400 italic">Updating in real-time...</span>
        </div>
        <LogTable logs={logs} />
      </main>
    </div>
  );
}

export default App;
